import type { Stats, HistogramBin } from './types'

const sort = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const sum = (arr: number[]): number => arr.reduce((a, b) => a + b, 0)

const quantile = (sorted: number[], q: number): number => {
  const pos = (sorted.length - 1) * q
  const base = Math.floor(pos)
  const rest = pos - base
  if (sorted[base + 1] !== undefined) {
    return sorted[base] + rest * (sorted[base + 1] - sorted[base])
  }
  return sorted[base]
}

export const computeStats = (values: number[]): Stats => {
  const sorted = sort(values)
  const n = sorted.length
  const mean = sum(sorted) / n

  const mid = Math.floor(n / 2)
  const median = n % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2

  const freqMap = new Map<number, number>()
  for (const v of sorted) {
    freqMap.set(v, (freqMap.get(v) ?? 0) + 1)
  }
  let maxFreq = 0
  for (const count of freqMap.values()) {
    if (count > maxFreq) maxFreq = count
  }
  const mode = maxFreq > 1
    ? [...freqMap.entries()].filter(([, c]) => c === maxFreq).map(([v]) => v)
    : []

  const variance = sum(sorted.map(v => (v - mean) ** 2)) / n
  const standardDeviation = Math.sqrt(variance)

  const min = sorted[0]
  const max = sorted[n - 1]
  const range = max - min

  const q1 = quantile(sorted, 0.25)
  const q3 = quantile(sorted, 0.75)
  const iqr = q3 - q1

  return { mean, median, mode, standardDeviation, variance, min, max, range, q1, q3, iqr, count: n }
}

export const buildHistogramBins = (values: number[], binCount = 10): HistogramBin[] => {
  const sorted = sort(values)
  const min = sorted[0]
  const max = sorted[sorted.length - 1]
  const binWidth = (max - min) / binCount || 1

  const bins: HistogramBin[] = Array.from({ length: binCount }, (_, i) => ({
    lower: min + i * binWidth,
    upper: min + (i + 1) * binWidth,
    count: 0,
  }))

  for (const v of sorted) {
    let idx = Math.floor((v - min) / binWidth)
    if (idx >= binCount) idx = binCount - 1
    bins[idx].count++
  }

  return bins
}

export const parseInput = (raw: string): number[] => {
  const trimmed = raw.trim()
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter(v => !Number.isNaN(v))
  }
  return trimmed
    .split(',')
    .map(s => Number(s.trim()))
    .filter(v => !Number.isNaN(v))
}

export const formatNum = (n: number): string =>
  Number.isInteger(n) ? String(n) : n.toFixed(4)

