/* ── Stat card for a single dataset ── */

const renderStatCard = (dws: DatasetWithStats, idx: number) => {
  const { dataset, stats } = dws
  const accent = colorFor(idx)

  const statEntries: [string, string][] = [
    ['Count', String(stats.count)],
    ['Mean', formatNum(stats.mean)],
    ['Median', formatNum(stats.median)],
    ['Mode', stats.mode.length ? stats.mode.map(formatNum).join(', ') : 'none'],
    ['Std Dev', formatNum(stats.standardDeviation)],
    ['Variance', formatNum(stats.variance)],
    ['Min', formatNum(stats.min)],
    ['Max', formatNum(stats.max)],
    ['Range', formatNum(stats.range)],
    ['Q1', formatNum(stats.q1)],
    ['Q3', formatNum(stats.q3)],
    ['IQR', formatNum(stats.iqr)],
  ]

  return h('div', { style: styles.card },
    h('div', { style: { ...styles.cardTitle, color: accent } }, dataset.name),
    h('div', { style: styles.statsGrid },
      ...statEntries.map(([label, value]) =>
        h('div', { style: styles.statItem },
          h('span', { style: styles.statLabel }, label),
          h('span', { style: styles.statValue }, value),
        ),
      ),
    ),
  )
}

/* ── Box plot SVG ── */

const renderBoxPlot = (datasets: DatasetWithStats[]) => {
  const allValues = datasets.flatMap(d => d.dataset.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const spread = globalMax - globalMin || 1

  const width = 600
  const plotLeft = 20
  const plotRight = width - 20
  const plotW = plotRight - plotLeft
  const rowHeight = 50
  const svgHeight = datasets.length * rowHeight + 40

  const scale = (v: number) => plotLeft + ((v - globalMin) / spread) * plotW

  const rows = datasets.map((dws, i) => {
    const { stats } = dws
    const y = i * rowHeight + 30
    const boxH = 24
    const mid = y + boxH / 2
    const color = colorFor(i)

    return h(Fragment, {},
      // whisker line
      h('line', { x1: String(scale(stats.min)), y1: String(mid), x2: String(scale(stats.max)), y2: String(mid), stroke: color, 'stroke-width': '1.5' }),
      // min cap
      h('line', { x1: String(scale(stats.min)), y1: String(y + 4), x2: String(scale(stats.min)), y2: String(y + boxH - 4), stroke: color, 'stroke-width': '1.5' }),
      // max cap
      h('line', { x1: String(scale(stats.max)), y1: String(y + 4), x2: String(scale(stats.max)), y2: String(y + boxH - 4), stroke: color, 'stroke-width': '1.5' }),
      // box
      h('rect', { x: String(scale(stats.q1)), y: String(y), width: String(scale(stats.q3) - scale(stats.q1)), height: String(boxH), fill: color, opacity: '0.25', stroke: color, 'stroke-width': '1.5', rx: '3' }),
      // median line
      h('line', { x1: String(scale(stats.median)), y1: String(y), x2: String(scale(stats.median)), y2: String(y + boxH), stroke: color, 'stroke-width': '2.5' }),
      // label
      h('text', { x: String(plotLeft - 4), y: String(mid + 4), 'text-anchor': 'end', 'font-size': '11', fill: color, 'font-weight': '600' }, dws.dataset.name),
    )
  })

  // tick marks
  const tickCount = 6
  const ticks = Array.from({ length: tickCount }, (_, i) => globalMin + (spread * i) / (tickCount - 1))
  const tickEls = ticks.map(v =>
    h(Fragment, {},
      h('line', { x1: String(scale(v)), y1: String(svgHeight - 16), x2: String(scale(v)), y2: String(svgHeight - 12), stroke: '#94a3b8', 'stroke-width': '1' }),
      h('text', { x: String(scale(v)), y: String(svgHeight - 2), 'text-anchor': 'middle', 'font-size': '10', fill: '#64748b' }, formatNum(v)),
    ),
  )

  return h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, 'Box Plot'),
    h('div', { style: styles.svgContainer },
      h('svg', { width: String(width), height: String(svgHeight), viewBox: `0 0 ${width} ${svgHeight}`, xmlns: 'http://www.w3.org/2000/svg' },
        // axis line
        h('line', { x1: String(plotLeft), y1: String(svgHeight - 16), x2: String(plotRight), y2: String(svgHeight - 16), stroke: '#cbd5e1', 'stroke-width': '1' }),
        ...tickEls,
        ...rows,
      ),
    ),
  )
}

/* ── Histogram SVG ── */

const renderHistogram = (datasets: DatasetWithStats[]) => {
  const width = 600
  const height = 260
  const margin = { top: 20, right: 20, bottom: 36, left: 44 }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const binCount = 12
  const allBins: { bins: HistogramBin[]; idx: number }[] = datasets.map((dws, idx) => ({
    bins: buildHistogramBins(dws.dataset.values, binCount),
    idx,
  }))

  const maxCount = Math.max(...allBins.flatMap(b => b.bins.map(bin => bin.count)), 1)
  const globalMin = Math.min(...datasets.flatMap(d => d.dataset.values))
  const globalMax = Math.max(...datasets.flatMap(d => d.dataset.values))
  const spread = globalMax - globalMin || 1

  const scaleX = (v: number) => margin.left + ((v - globalMin) / spread) * plotW
  const scaleY = (c: number) => margin.top + plotH - (c / maxCount) * plotH
  const barGroupWidth = plotW / binCount
  const barWidth = barGroupWidth / datasets.length

  const bars = allBins.flatMap(({ bins, idx }) =>
    bins.map((bin, bi) => {
      const x = margin.left + bi * barGroupWidth + idx * barWidth
      const bh = (bin.count / maxCount) * plotH
      const y = margin.top + plotH - bh
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(Math.max(barWidth - 1, 1)),
        height: String(bh),
        fill: colorFor(idx),
        opacity: '0.7',
      })
    }),
  )

  // Y axis ticks
  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount }, (_, i) => Math.round((maxCount * i) / (yTickCount - 1)))
  const yTickEls = yTicks.map(c =>
    h(Fragment, {},
      h('line', { x1: String(margin.left), y1: String(scaleY(c)), x2: String(margin.left + plotW), y2: String(scaleY(c)), stroke: '#e2e8f0', 'stroke-width': '1' }),
      h('text', { x: String(margin.left - 6), y: String(scaleY(c) + 4), 'text-anchor': 'end', 'font-size': '10', fill: '#64748b' }, String(c)),
    ),
  )

  // X axis ticks
  const xTickCount = 6
  const xTicks = Array.from({ length: xTickCount }, (_, i) => globalMin + (spread * i) / (xTickCount - 1))
  const xTickEls = xTicks.map(v =>
    h(Fragment, {},
      h('text', { x: String(scaleX(v)), y: String(height - 4), 'text-anchor': 'middle', 'font-size': '10', fill: '#64748b' }, formatNum(v)),
    ),
  )

  // Legend
  const legendEls = datasets.map((dws, idx) =>
    h(Fragment, {},
      h('rect', { x: String(margin.left + idx * 100), y: '4', width: '10', height: '10', fill: colorFor(idx), rx: '2' }),
      h('text', { x: String(margin.left + idx * 100 + 14), y: '13', 'font-size': '11', fill: '#334155' }, dws.dataset.name),
    ),
  )

  return h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, 'Histogram'),
    h('div', { style: styles.svgContainer },
      h('svg', { width: String(width), height: String(height), viewBox: `0 0 ${width} ${height}`, xmlns: 'http://www.w3.org/2000/svg' },
        ...yTickEls,
        ...bars,
        // axes
        h('line', { x1: String(margin.left), y1: String(margin.top), x2: String(margin.left), y2: String(margin.top + plotH), stroke: '#cbd5e1', 'stroke-width': '1' }),
        h('line', { x1: String(margin.left), y1: String(margin.top + plotH), x2: String(margin.left + plotW), y2: String(margin.top + plotH), stroke: '#cbd5e1', 'stroke-width': '1' }),
        ...xTickEls,
        ...legendEls,
      ),
    ),
  )
}

/* ── Comparison summary table ── */

const renderComparisonTable = (datasets: DatasetWithStats[]) => {
  const statKeys: { label: string; key: string }[] = [
    { label: 'Count', key: 'count' },
    { label: 'Mean', key: 'mean' },
    { label: 'Median', key: 'median' },
    { label: 'Mode', key: 'mode' },
    { label: 'Std Dev', key: 'standardDeviation' },
    { label: 'Variance', key: 'variance' },
    { label: 'Min', key: 'min' },
    { label: 'Max', key: 'max' },
    { label: 'Range', key: 'range' },
    { label: 'Q1', key: 'q1' },
    { label: 'Q3', key: 'q3' },
    { label: 'IQR', key: 'iqr' },
  ]

  const getValue = (stats: DatasetWithStats['stats'], key: string): string => {
    if (key === 'mode') return stats.mode.length ? stats.mode.map(formatNum).join(', ') : 'none'
    return formatNum(stats[key as keyof typeof stats] as number)
  }

  return h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, 'Comparison Summary'),
    h('table', { style: styles.table },
      h('thead', {},
        h('tr', {},
          h('th', { style: styles.th }, 'Statistic'),
          ...datasets.map((dws, i) =>
            h('th', { style: { ...styles.th, color: colorFor(i) } }, dws.dataset.name),
          ),
        ),
      ),
      h('tbody', {},
        ...statKeys.map(({ label, key }) =>
          h('tr', {},
            h('td', { style: { ...styles.td, fontWeight: '600' } }, label),
            ...datasets.map(dws =>
              h('td', { style: styles.td }, getValue(dws.stats, key)),
            ),
          ),
        ),
      ),
    ),
  )
}

/* ── Main render ── */

export const renderPage = (datasets: DatasetWithStats[], error?: string) => {
  const hasData = datasets.length > 0

  return h('div', { style: styles.root },
    h('div', { style: styles.heading }, 'Statistics Calculator'),

    // Input form
    h('form', { style: styles.form, 'p-trigger': 'submit:addDataset' },
      h('input', {
        type: 'text',
        name: 'datasetName',
        placeholder: 'Dataset name',
        style: { ...styles.input, ...styles.nameInput },
        required: 'true',
      }),
      h('input', {
        type: 'text',
        name: 'datasetValues',
        placeholder: '1, 2, 3, 4 or [1, 2, 3, 4]',
        style: { ...styles.input, ...styles.dataInput },
        required: 'true',
      }),
      h('button', { type: 'submit', style: styles.button }, 'Add Dataset'),
      ...(hasData
        ? [h('button', { type: 'button', style: styles.clearButton, 'p-trigger': 'click:clearAll' }, 'Clear All')]
        : []),
    ),

    // Error message
    ...(error
      ? [h('div', { style: { color: '#ef4444', marginBottom: '16px', fontSize: '14px' } }, error)]
      : []),

    // Empty state
    ...(!hasData
      ? [h('div', { style: styles.emptyState },
          h('div', { style: { fontSize: '18px', marginBottom: '8px' } }, 'No datasets yet'),
          h('div', {}, 'Enter comma-separated numbers or a JSON array above to get started.'),
        )]
      : []),

    // Stat cards
    ...datasets.map((dws, i) => renderStatCard(dws, i)),

    // Charts (need at least one dataset)
    ...(hasData
      ? [
          renderBoxPlot(datasets),
          renderHistogram(datasets),
        ]
      : []),

    // Comparison table (need 2+ datasets)
    ...(datasets.length >= 2
      ? [renderComparisonTable(datasets)]
      : []),
  )
}

import { createSSR } from 'plaited'
import type { Dataset, DatasetWithStats } from './types'
import { computeStats, parseInput } from './stats'
import { renderPage } from './render'

const DATA_PATH = './data/datasets.json'

const loadDatasets = async (): Promise<Dataset[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return (await file.json()) as Dataset[]
  }
  return []
}

const saveDatasets = async (datasets: Dataset[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(datasets, null, 2))
}

const buildDatasetsWithStats = (datasets: Dataset[]): DatasetWithStats[] =>
  datasets.map(dataset => ({
    dataset,
    stats: computeStats(dataset.values),
  }))

/* ── Route handlers ── */

const handleAddDataset = async (formData: FormData): Promise<Response> => {
  const name = (formData.get('datasetName') as string | null)?.trim()
  const rawValues = (formData.get('datasetValues') as string | null)?.trim()

  if (!name || !rawValues) {
    return renderResponse(await loadDatasets(), 'Please provide both a name and values.')
  }

  let values: number[]
  try {
    values = parseInput(rawValues)
  } catch {
    return renderResponse(await loadDatasets(), 'Invalid input. Use comma-separated numbers or a JSON array.')
  }

  if (values.length === 0) {
    return renderResponse(await loadDatasets(), 'No valid numbers found in input.')
  }

  const datasets = await loadDatasets()
  const existing = datasets.findIndex(d => d.name === name)
  if (existing !== -1) {
    datasets[existing] = { name, values }
  } else {
    datasets.push({ name, values })
  }
  await saveDatasets(datasets)

  return renderResponse(datasets)
}

const handleClearAll = async (): Promise<Response> => {
  await saveDatasets([])
  return renderResponse([])
}

const handleRemoveDataset = async (name: string): Promise<Response> => {
  const datasets = (await loadDatasets()).filter(d => d.name !== name)
  await saveDatasets(datasets)
  return renderResponse(datasets)
}

const renderResponse = async (datasets: Dataset[], error?: string): Promise<Response> => {
  const withStats = buildDatasetsWithStats(datasets)
  const ssr = createSSR()
  const html = ssr(renderPage(withStats, error))
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

/* ── Server ── */

export default {
  port: 3000,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)

    if (req.method === 'POST' && url.pathname === '/add') {
      const formData = await req.formData()
      return handleAddDataset(formData)
    }

    if (req.method === 'POST' && url.pathname === '/clear') {
      return handleClearAll()
    }

    if (req.method === 'POST' && url.pathname.startsWith('/remove/')) {
      const name = decodeURIComponent(url.pathname.slice('/remove/'.length))
      return handleRemoveDataset(name)
    }

    // Default: render current state
    const datasets = await loadDatasets()
    return renderResponse(datasets)
  },
}
